if deviceToDelete == nil {
	return nil, trace.NotFound("MFA device %q does not exist", deviceName)
}

// Determine the type of device being deleted
var deviceTypeToDelete types.SecondFactorType
switch deviceToDelete.Device.(type) {
case *types.MFADevice_Totp:
	deviceTypeToDelete = types.SecondFactorType_SECOND_FACTOR_TYPE_OTP
case *types.MFADevice_U2F, *types.MFADevice_Webauthn:
	deviceTypeToDelete = types.SecondFactorType_SECOND_FACTOR_TYPE_WEBAUTHN
case *types.MFADevice_Sso:
	deviceTypeToDelete = types.SecondFactorType_SECOND_FACTOR_TYPE_SSO
default:
	a.logger.WarnContext(ctx, "Unknown device type in deletion check", "device_type", logutils.TypeAttr(deviceToDelete.Device))
}

// Check if deletion would violate second factor requirements
allowedFactors := readOnlyAuthPref.GetSecondFactors()
isSecondFactorOTPAllowed := readOnlyAuthPref.IsSecondFactorTOTPAllowed()
isSecondFactorWebauthnAllowed := readOnlyAuthPref.IsSecondFactorWebauthnAllowed()

// Get remaining device counts by type (excluding the device being deleted)
remainingOTPDevices := remainingDevices[types.SecondFactorType_SECOND_FACTOR_TYPE_OTP]
remainingWebauthnDevices := remainingDevices[types.SecondFactorType_SECOND_FACTOR_TYPE_WEBAUTHN]

// Determine the second factor mode based on allowed factors and enforcement status
switch {
case len(allowedFactors) == 0:
	// Second factor is off - allow any deletion
case isSecondFactorOTPAllowed && !isSecondFactorWebauthnAllowed:
	// Only TOTP is allowed
	if deviceTypeToDelete == types.SecondFactorType_SECOND_FACTOR_TYPE_OTP && remainingOTPDevices == 0 {
		return nil, trace.BadParameter("cannot delete the last TOTP device for this user; add a replacement device first to avoid getting locked out")
	}
case !isSecondFactorOTPAllowed && isSecondFactorWebauthnAllowed:
	// Only Webauthn is allowed
	if deviceTypeToDelete == types.SecondFactorType_SECOND_FACTOR_TYPE_WEBAUTHN && remainingWebauthnDevices == 0 {
		return nil, trace.BadParameter("cannot delete the last WebAuthn device for this user; add a replacement device first to avoid getting locked out")
	}
case isSecondFactorOTPAllowed && isSecondFactorWebauthnAllowed:
	// Both TOTP and Webauthn are allowed
	if readOnlyAuthPref.IsSecondFactorEnforced() {
		// SecondFactorOn - all MFA devices are required
		totalRemaining := remainingOTPDevices + remainingWebauthnDevices
		if totalRemaining == 0 {
			return nil, trace.BadParameter("cannot delete the last MFA device for this user; add a replacement device first to avoid getting locked out")
		}
	}
	// SecondFactorOptional - allow deletion even if it leaves no devices
default:
	a.logger.WarnContext(ctx, "Unknown second factor configuration", "allowed_factors", allowedFactors)
}

