  4731→// deleteMFADeviceSafely deletes the user's mfa device while preventing users
  4732→// from locking themselves out of their account.
  4733→//
  4734→// Deletes are not allowed in the following situations:
  4735→//   - Last MFA device when the cluster requires MFA
  4736→//   - Last resident key credential in a passwordless-capable cluster (avoids
  4737→//     passwordless users from locking themselves out).
  4738→func (a *Server) deleteMFADeviceSafely(ctx context.Context, user, deviceName string) (*types.MFADevice, error) {
  4739→	mfaDevices, err := a.Services.GetMFADevices(ctx, user, true)
  4740→	if err != nil {
  4741→		return nil, trace.Wrap(err)
