  4760→		if d.GetName() == deviceName || d.Id == deviceName {
  4761→			deviceToDelete = d
  4762→			switch d.Device.(type) {
  4763→			case *types.MFADevice_Totp, *types.MFADevice_U2F, *types.MFADevice_Webauthn:
  4764→			case *types.MFADevice_Sso:
  4765→				return nil, trace.BadParameter("cannot delete ephemeral SSO MFA device")
  4766→			default:
  4767→				return nil, trace.NotImplemented("cannot delete device of type %T", d.Device)
  4768→			}
