  4774→			remainingDevices[types.SecondFactorType_SECOND_FACTOR_TYPE_OTP]++
  4775→		case *types.MFADevice_U2F, *types.MFADevice_Webauthn:
  4776→			remainingDevices[types.SecondFactorType_SECOND_FACTOR_TYPE_WEBAUTHN]++
  4777→		case *types.MFADevice_Sso:
  4778→			remainingDevices[types.SecondFactorType_SECOND_FACTOR_TYPE_SSO]++
  4779→		default:
